    const caseData = {
      case1: { title: "Реверсивный инжиниринг детали по физическому образцу", stats: [["Формат входа", "Образец или скан"], ["Фокус", "Редактируемая модель"], ["Результат", "CAD для работы"]], columns: [{ title: "Задача", items: ["есть физическая деталь, но нет исходной модели", "нужно восстановить геометрию и сохранить важные сопряжения", "результат должен подходить для дальнейших правок"] }, { title: "Что делаем", items: ["получаем цифровую базу через сканирование или анализ образца", "собираем инженерную модель, а не просто сетку", "проверяем критичные размеры и готовим результат под следующий этап"] }, { title: "Что получает клиент", items: ["редактируемую модель для дальнейшей работы", "понятный маршрут правок и адаптаций", "меньше риска потерять логику детали"] }], footer: "Подходит, когда нужна не просто копия формы, а рабочая инженерная модель." },
      case2: { title: "Функциональный прототип для проверки формы и сборки", stats: [["Формат входа", "Идея, эскиз или CAD"], ["Фокус", "Быстрый тест"], ["Результат", "Образец в руках"]], columns: [{ title: "Задача", items: ["нужно быстро увидеть форму в реальности", "важно проверить посадку, стыки или удобство", "не хочется сразу идти в дорогой финальный цикл"] }, { title: "Что делаем", items: ["подбираем достаточную точность под цель проверки", "изготавливаем прототип для быстрого теста", "фиксируем, что менять на следующем этапе"] }, { title: "Что получает клиент", items: ["быстрое снижение неопределенности", "материал для обсуждения и решений", "экономию времени и бюджета на раннем этапе"] }], footer: "Подходит, когда нужно быстро проверить форму, сборку или эргономику." },
      case3: { title: "Награда, арт-объект или выставочный предмет", stats: [["Формат входа", "Эскиз и референсы"], ["Фокус", "Подача и качество"], ["Результат", "Объект презентационного уровня"]], columns: [{ title: "Задача", items: ["нужен выразительный предмет, а не просто печать", "важны и внешний вид, и технологичность", "нужно учесть сборку, поверхность и подачу"] }, { title: "Что делаем", items: ["соединяем дизайн и производственную логику", "подбираем материал и постобработку", "готовим объект под реальное использование или экспозицию"] }, { title: "Что получает клиент", items: ["предмет, который хорошо выглядит вживую", "меньше риска конфликтов между идеей и производством", "более сильную финальную подачу"] }], footer: "Подходит для наград, арт-объектов и выставочных предметов." }
    };
    const caseItems = document.querySelectorAll('.case-item');
    const caseTitle = document.getElementById('caseTitle');
    const caseStats = document.getElementById('caseStats');
    const caseBody = document.getElementById('caseBody');
    const caseFooterText = document.getElementById('caseFooterText');
    function renderCase(id) {
      const data = caseData[id]; if (!data) return;
      caseTitle.textContent = data.title; caseFooterText.textContent = data.footer;
      caseStats.innerHTML = data.stats.map(([label, value]) => `<div class="case-stat"><strong>${label}</strong><span>${value}</span></div>`).join('');
      caseBody.innerHTML = data.columns.map(col => `<div class="case-column"><strong>${col.title}</strong><ul>${col.items.map(item => `<li>${item}</li>`).join('')}</ul></div>`).join('');
    }
    caseItems.forEach(item => item.addEventListener('click', () => { caseItems.forEach(btn => btn.classList.remove('is-active')); item.classList.add('is-active'); renderCase(item.dataset.case); }));
    renderCase('case1');

    const serviceTabs = document.querySelectorAll('.service-tab');
    const servicePanels = document.querySelectorAll('.service-panel');
    serviceTabs.forEach(tab => {
      tab.addEventListener('click', () => {
        const key = tab.dataset.service;
        serviceTabs.forEach(btn => { btn.classList.remove('is-active'); btn.setAttribute('aria-selected', 'false'); });
        servicePanels.forEach(panel => panel.classList.remove('is-active'));
        tab.classList.add('is-active'); tab.setAttribute('aria-selected', 'true');
        const target = document.querySelector(`.service-panel[data-panel="${key}"]`); if (target) target.classList.add('is-active');
        const select = document.getElementById('projectType'); if (select && ['scan','reverse','prototype','print'].includes(key)) { select.value = key; updateEstimate(); }
      });
    });

    document.querySelectorAll('.faq-item').forEach(item => {
      const button = item.querySelector('.faq-q'); const content = item.querySelector('.faq-a');
      button.addEventListener('click', () => {
        const isOpen = item.classList.contains('is-open');
        document.querySelectorAll('.faq-item').forEach(other => { other.classList.remove('is-open'); other.querySelector('.faq-a').style.maxHeight = 0; });
        if (!isOpen) { item.classList.add('is-open'); content.style.maxHeight = content.scrollHeight + 'px'; }
      });
    });

    const estimateForm = document.getElementById('estimateForm');
    const scoreRing = document.getElementById('scoreRing');
    const scoreValue = document.getElementById('scoreValue');
    const estimateHeadline = document.getElementById('estimateHeadline');
    const estimateText = document.getElementById('estimateText');
    const estimateChips = document.getElementById('estimateChips');
    const estimateBullets = document.getElementById('estimateBullets');
    const optionGroups = {};
    document.querySelectorAll('.option').forEach(btn => {
      const group = btn.dataset.group; if (!optionGroups[group]) optionGroups[group] = []; optionGroups[group].push(btn);
      btn.addEventListener('click', () => { optionGroups[group].forEach(el => el.classList.remove('is-active')); btn.classList.add('is-active'); updateEstimate(); });
    });
    function activeOptionValue(groupName) { const active = document.querySelector(`.option[data-group="${groupName}"].is-active`); return active ? active.dataset.value : ''; }
    function updateEstimate() {
      const type = document.getElementById('projectType').value;
      const goal = document.getElementById('projectGoal').value;
      const source = document.getElementById('projectSource').value;
      const scale = document.getElementById('projectScale').value;
      const notes = document.getElementById('projectNotes').value.trim();
      const priority = activeOptionValue('priority');
      const deadline = activeOptionValue('deadline');
      let score = 58;
      if (source === 'object' || source === 'file') score += 8;
      if (goal === 'production' || goal === 'adapt' || goal === 'restore') score += 6;
      if (notes.length > 35) score += 6;
      if (notes.length > 110) score += 4;
      if (scale === 'small') score += 3;
      if (scale === 'large') score -= 4;
      if (deadline === 'rush') score -= 6;
      if (priority === 'quality') score += 3;
      if (type === 'mixed') score -= 2;
      score = Math.max(42, Math.min(92, score));
      const complexityMap = { small: 'Низкая', medium: 'Средняя', large: 'Повышенная' };
      const routeMap = { scan: 'Сканирование → цифровая база', reverse: 'Сканирование / анализ → CAD', prototype: 'Подготовка → прототип → правки', print: 'Подготовка → печать → финиш', mixed: 'Комбинированный маршрут' };
      const rhythmMap = { rush: 'Срочный', normal: 'Стандартный', planned: 'Плановый' };
      const typeHeadlines = { scan: 'Хороший старт для сканирования объекта.', reverse: 'Сценарий подходит для старта реверсивного инжиниринга.', prototype: 'Сценарий подходит для быстрого запуска прототипа.', print: 'Сценарий подходит для подготовки к изготовлению.', mixed: 'Комплексная задача требует чуть больше вводных, но логика уже собрана.' };
      const goalText = { demo: 'Фокус на подаче и внешнем виде.', test: 'Фокус на проверке формы, посадки или механики.', restore: 'Фокус на восстановлении или повторении геометрии.', adapt: 'Фокус на инженерной доработке.', production: 'Фокус на результате для следующего производственного шага.' };
      let bullets = [];
      if (source === 'idea') bullets.push('Добавить 2-4 референса или похожих фото.');
      if (source === 'object') bullets.push('Сфотографировать объект с нескольких сторон и указать габариты.');
      if (source === 'file') bullets.push('Подготовить файл и коротко описать цель результата.');
      if (deadline === 'rush') bullets.push('Сразу отметить крайний срок и что обязательно успеть.');
      if (priority === 'quality') bullets.push('Уточнить, где критична точность: размеры, посадки или внешний вид.');
      if (priority === 'budget') bullets.push('Сразу обозначить желаемый бюджет и допустимый компромисс.');
      if (notes.length < 35) bullets.push('Добавить одно-два предложения о том, как будет использоваться результат.');
      bullets.push('Собрать бриф ниже, чтобы не потерять важные детали.');
      scoreRing.style.setProperty('--progress', score); scoreValue.textContent = score;
      estimateHeadline.textContent = typeHeadlines[type];
      estimateText.textContent = `${goalText[goal]} Сейчас уровень готовности - ${score} из 100. Чем точнее вводные по сроку, применению и ограничениям, тем быстрее можно собрать маршрут работы.`;
      estimateChips.innerHTML = `<span class="pill"><strong>Маршрут</strong> ${routeMap[type]}</span><span class="pill"><strong>Сложность</strong> ${complexityMap[scale]}</span><span class="pill"><strong>Ритм</strong> ${rhythmMap[deadline]}</span>`;
      estimateBullets.innerHTML = bullets.map(item => `<li>${item}</li>`).join('');
    }
    estimateForm.addEventListener('input', updateEstimate); estimateForm.addEventListener('change', updateEstimate); updateEstimate();

    const briefOutput = document.getElementById('briefOutput');
    const generateBriefBtn = document.getElementById('generateBrief');
    const copyBriefBtn = document.getElementById('copyBrief');
    function buildBrief() {
      const name = document.getElementById('briefName').value.trim() || 'Не указано';
      const contact = document.getElementById('briefContact').value.trim() || 'Не указано';
      const task = document.getElementById('briefTask').value;
      const deadline = document.getElementById('briefDeadline').value;
      const assets = document.getElementById('briefAssets').value.trim() || 'Не указано';
      const desc = document.getElementById('briefDesc').value.trim() || 'Не указано';
      return [`Здравствуйте. Меня зовут ${name}.`,`Контакт для связи: ${contact}.`,``,`Тип задачи: ${task}.`,`Желаемый срок: ${deadline}.`,`Что уже есть: ${assets}.`,``,`Краткое описание задачи:`,`${desc}`,``,`Прошу подсказать оптимальный маршрут работы и что еще подготовить для быстрого старта проекта.`].join('\n');
    }
    generateBriefBtn.addEventListener('click', () => { briefOutput.textContent = buildBrief(); });
    copyBriefBtn.addEventListener('click', async () => {
      const text = briefOutput.textContent.includes('Нажмите «Собрать бриф»') ? buildBrief() : briefOutput.textContent;
      try { await navigator.clipboard.writeText(text); copyBriefBtn.textContent = 'Скопировано'; setTimeout(() => { copyBriefBtn.innerHTML = 'Скопировать <span class="arrow" aria-hidden="true"></span>'; }, 1600); }
      catch (err) { copyBriefBtn.textContent = 'Не удалось скопировать'; setTimeout(() => { copyBriefBtn.innerHTML = 'Скопировать <span class="arrow" aria-hidden="true"></span>'; }, 1600); }
    });

    const scrollProgress = document.getElementById('scrollProgress');
    const sectionIds = ['top','story','services','model','workflow','estimate','cases','compare','faq','contact'];
    const navLinks = [...document.querySelectorAll('.nav-link')];
    const railLinks = [...document.querySelectorAll('.rail-link')];
    const sections = sectionIds.map(id => document.getElementById(id)).filter(Boolean);
    function setActiveNav(targetId) { navLinks.forEach(link => link.classList.toggle('is-active', link.getAttribute('href') === `#${targetId}`)); railLinks.forEach(link => link.classList.toggle('is-active', link.getAttribute('href') === `#${targetId}`)); }
    function onScroll() {
      const doc = document.documentElement; const max = doc.scrollHeight - window.innerHeight; const progress = max > 0 ? (window.scrollY / max) * 100 : 0; scrollProgress.style.width = progress + '%';
      let current = 'top'; const offset = window.innerHeight * 0.24; sections.forEach(section => { const top = section.getBoundingClientRect().top; if (top <= offset) current = section.id; }); setActiveNav(current);
    }
    window.addEventListener('scroll', onScroll, { passive: true }); onScroll();
    const observer = new IntersectionObserver((entries) => { entries.forEach(entry => { if (entry.isIntersecting) entry.target.classList.add('is-visible'); }); }, { threshold: .16 });
    document.querySelectorAll('.reveal').forEach(el => observer.observe(el));
  

